// ---------------------------------------------------------------------------
// Uber Base token values — from benchmark
// Explicit from benchmark: 250 / 200 / 300 / 400 / 500 / 600 / 800 / 1000ms
// timing100 = 250ms is the first documented, timing700 = 600ms, timing1000 = 1000ms
// Mapping from benchmark context:
// ---------------------------------------------------------------------------
const UBER_DURATIONS = [
  { name: 'timing100', value: 250, note: 'Lightest weight' },
  { name: 'timing200', value: 200, note: 'Faster micro-interaction' },
  { name: 'timing300', value: 300, note: '' },
  { name: 'timing400', value: 400, note: '' },
  { name: 'timing500', value: 500, note: '' },
  { name: 'timing600', value: 600, note: '' },
  { name: 'timing700', value: 600, note: '' },
  { name: 'timing1000', value: 1000, note: 'Revised after snackbar perceived too slow in production' },
];

const UBER_EASINGS = [
  {
    name: 'easeOutCurve',
    curve: [0.2, 0.8, 0.4, 1],
    desc: 'Decelerate — elements entering or arriving',
  },
  {
    name: 'easeInCurve',
    curve: [0.8, 0.2, 0.6, 1],
    desc: 'Accelerate — elements departing',
  },
  {
    name: 'easeInOutCurve',
    curve: [0.4, 0, 0.2, 1],
    desc: 'Smooth accel + decel — repositioning within screen',
  },
];

function cb([x1, y1, x2, y2]) {
  return `cubic-bezier(${x1}, ${y1}, ${x2}, ${y2})`;
}

function easingSVG([x1, y1, x2, y2], color = '#000') {
  const pts = [];
  for (let i = 0; i <= 20; i++) {
    const t = i / 20;
    const bx = 3*(1-t)*(1-t)*t*x1 + 3*(1-t)*t*t*x2 + t*t*t;
    const by = 3*(1-t)*(1-t)*t*y1 + 3*(1-t)*t*t*y2 + t*t*t;
    pts.push([bx * 40, (1 - by) * 8]);
  }
  const d = pts.map(([x, y], i) => `${i === 0 ? 'M' : 'L'}${x.toFixed(1)} ${y.toFixed(1)}`).join(' ');
  return `<svg width="40" height="8" viewBox="0 0 40 8" style="overflow:visible;display:inline-block;vertical-align:middle">
    <path d="${d}" fill="none" stroke="${color}" stroke-width="1.5"/>
  </svg>`;
}

